const input = $input.first().json;

const data = input.output;

// Fecha con zona horaria española automática (verano e invierno)
const now = new Date();

const fechaFormateada = now.toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).replace(',', ' -');

return [{
  json: {
    decision: data.decision,
    nombre: data.nombre,
    estrellas: data.estrellas,
    comentario: data.comentario,
    motivo: data.motivo,
    "fecha y hora": fechaFormateada
  }
}];

const input = $input.first().json;

const now = new Date();

// Fecha legible para Telegram y Google Sheets
const fechaLegible = now.toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).replace(',', ' -');

// Fecha en formato ISO para Supabase
const fechaISO = now.toLocaleString('sv-SE', {
  timeZone: 'Europe/Madrid'
}).replace(' ', 'T');

return [{
  json: {
    decision: input.decision,
    nombre: input.nombre,
    estrellas: input.estrellas,
    comentario: input.comentario,
    motivo: input.motivo,
    "fecha y hora": fechaLegible,
    "fecha_iso": fechaISO
  }
}];

